import pandas as pd
import numpy as np

def analyze_performance(csv_path="confusion_matrix.csv"):
    try:
        # Load the matrix generated by evaluate_models.py
        df = pd.read_csv(csv_path, index_col=0)
    except FileNotFoundError:
        print("[!] Error: confusion_matrix.csv not found. Run evaluate_models.py first!")
        return

    # Calculate Accuracy for each website (Diagonal value / Total row sum)
    accuracies = {}
    for website in df.index:
        correct_guesses = df.loc[website, website]
        total_samples = df.loc[website].sum()
        
        if total_samples > 0:
            # FIX: Using the correct variable name here
            accuracies[website] = (correct_guesses / total_samples) * 100
        else:
            accuracies[website] = 0

    # Sort the results by accuracy percentage
    sorted_sites = sorted(accuracies.items(), key=lambda x: x[1], reverse=True)

    print("\n" + "="*45)
    print("🏆 TOP 5: MOST IDENTIFIABLE SITES")
    print("-" * 45)
    for site, acc in sorted_sites[:5]:
        print(f"{site:<20} | Accuracy: {acc:>6.2f}%")

    print("\n" + "="*45)
    print("⚠️ BOTTOM 5: MOST MASKED SITES")
    print("-" * 45)
    # Filter out 0% sites for the bottom 5 if you want to see the 'hardest' ones that had data
    for site, acc in sorted_sites[-5:]:
        print(f"{site:<20} | Accuracy: {acc:>6.2f}%")
        
    print("\n" + "="*45)
    print(f"OVERALL ANALYZED SITES: {len(sorted_sites)}")
    print("="*45)

if __name__ == "__main__":
    analyze_performance()